What does the following program print?

```cpp
#include <iostream>

class Counter {
private:
    int m_count{ 3 };

public:
    void increment() { ++m_count; }
    int getCount() const { return m_count; }
};

int main() {
    Counter c;
    c.increment();
    c.increment();
    std::cout << c.getCount() << '\n';
    return 0;
}
```

