What does the following program print?

```cpp
#include <iostream>

struct Point {
    int x;
    int y;
};

class Pixel {
private:
    int m_x;
    int m_y;
public:
    Pixel(int x, int y) : m_x(x), m_y(y) {}
    void print() const {
        std::cout << m_x << ' ' << m_y << '\n';
    }
};

int main() {
    Point p{ 1, 2 };
    Pixel px{ 3, 4 };
    std::cout << p.x << ' ' << p.y << '\n';
    px.print();
    return 0;
}
```
